class Solution:
    def minCostConnectPoints(self, points):
        """
        :type points: List[List[int]]
        :rtype: int
        """
        n = len(points)
        edges = []

        # Create all edges with manhattan distance
        for i in range(n):
            for j in range(i + 1, n):
                dist = abs(points[i][0] - points[j][0]) + abs(points[i][1] - points[j][1])
                edges.append((dist, i, j))

        # Kruskal's algorithm with Union-Find
        edges.sort()
        parent = list(range(n))

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            px, py = find(x), find(y)
            if px != py:
                parent[px] = py
                return True
            return False

        total_cost = 0
        edges_used = 0

        for cost, i, j in edges:
            if union(i, j):
                total_cost += cost
                edges_used += 1
                if edges_used == n - 1:
                    break

        return total_cost
